def is_southeastern_village(village_name):
    southeastern_villages = {
        "Azaraegbelu", "Owerri", "Emekuku", "Ikeduru", "Aboh-Mbaise", "Emii"
    }
    return village_name in southeastern_villages

# Example usage:
print(is_southeastern_village("Azaraegbelu"))  # Output: True
print(is_southeastern_village("Lagos"))  # Output: False
